mapper.select:
select *
from `Inspection`
where group_name = #{groupName}
  and year = #{year}

mapper.update:
update `Inspection`
set feedback = #{feedback},
    modify_time = #{modifyTime}
where id = #{inspectionId}
  and group_name = #{groupName}

update `Inspection`
set attachment = #{attachment},
    modify_time = #{modifyTime}
where id = #{inspectionId}
  and group_name = #{groupName}

update `Inspection`
set is_accepted = true
where id = #{inspectionId}

update `Inspection`
set is_accepted = false
where id = #{inspectionId}
